SELECT COUNT(*) FROM servidor s WHERE LOWER(s.categoria) = LOWER('docente') AND LOWER(s.contrato) = LOWER('efetivos') AND LOWER(s.area_ingresso) = LOWER('educacao fisica') AND LOWER(s.sigla_campus) = LOWER('inh') AND s.saiu_do_ifg = FALSE AND s.pk_siape IN (SELECT chm.siape FROM calc_hora_aula_media chm WHERE chm.ano = 2023 AND chm.semestre = 1 AND LOWER(chm.sigla_campus) = LOWER('inh') AND LOWER(chm.area_ingresso) = LOWER('educacao fisica'))